changeSet.sql:
UPDATE feedback_session_logs
SET dedup_window_bucket = FLOOR(EXTRACT(EPOCH FROM "timestamp") * 1000 / 2000)::BIGINT
WHERE dedup_window_bucket IS NULL;

DELETE FROM feedback_session_logs
WHERE id IN (
    SELECT id
    FROM (
        SELECT id,
               ROW_NUMBER() OVER (
                   PARTITION BY student_id, session_id, feedback_session_log_type, dedup_window_bucket
                   ORDER BY "timestamp" ASC, id ASC
               ) AS rn
        FROM feedback_session_logs
    ) duplicate_rows
    WHERE duplicate_rows.rn > 1
);
